import React, { useState, useEffect, useCallback } from "react";
import { X, Plus, FileText, Star, Trash2 } from "lucide-react";
import { useAuth } from "../context/AuthContext";

const Templates = ({ onUseTemplate }) => {
  const { getAuthHeaders } = useAuth();
  const [templates, setTemplates] = useState({ user: [], public: [] });
  const [showModal, setShowModal] = useState(false);
  const [activeTab, setActiveTab] = useState("user");
  const [formData, setFormData] = useState({
    name: "",
    description: "",
    title: "",
    content: "",
    color: "#FFE4B5",
    category: "personal",
    tags: [],
  });

  const fetchTemplates = useCallback(async () => {
    try {
      const response = await fetch("http://localhost:5000/api/templates", {
        headers: getAuthHeaders(),
      });
      const data = await response.json();
      setTemplates({
        user: Array.isArray(data.user) ? data.user : [],
        public: Array.isArray(data.public) ? data.public : [],
      });
    } catch (error) {
      console.error("Lỗi khi tải templates:", error);
    }
  }, [getAuthHeaders]);

  useEffect(() => {
    fetchTemplates();
  }, [fetchTemplates]);

  const handleUseTemplate = async (templateId) => {
    try {
      const response = await fetch(
        `http://localhost:5000/api/templates/${templateId}/use`,
        {
          method: "POST",
          headers: getAuthHeaders(),
        }
      );
      const note = await response.json();
      if (onUseTemplate) {
        onUseTemplate(note);
      }
      await fetchTemplates();
    } catch (error) {
      console.error("Lỗi:", error);
    }
  };

  const handleCreateTemplate = async (e) => {
    e.preventDefault();
    try {
      const response = await fetch("http://localhost:5000/api/templates", {
        method: "POST",
        headers: getAuthHeaders(),
        body: JSON.stringify(formData),
      });
      if (response.ok) {
        await fetchTemplates();
        setShowModal(false);
        setFormData({
          name: "",
          description: "",
          title: "",
          content: "",
          color: "#FFE4B5",
          category: "personal",
          tags: [],
        });
      }
    } catch (error) {
      console.error("Lỗi:", error);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Bạn có chắc muốn xóa template này?")) return;
    try {
      await fetch(`http://localhost:5000/api/templates/${id}`, {
        method: "DELETE",
        headers: getAuthHeaders(),
      });
      await fetchTemplates();
    } catch (error) {
      console.error("Lỗi:", error);
    }
  };

  return (
    <>
      <div className="space-y-4">
        <div className="flex items-center justify-between">
          <h3 className="font-semibold">Templates</h3>
          <button
            onClick={() => setShowModal(true)}
            className="px-3 py-1 bg-blue-500 text-white rounded-lg hover:bg-blue-600 text-sm"
          >
            <Plus size={16} className="inline mr-1" />
            Tạo mới
          </button>
        </div>

        <div className="flex gap-2 border-b border-gray-200 dark:border-gray-700">
          <button
            onClick={() => setActiveTab("user")}
            className={`px-4 py-2 font-semibold ${
              activeTab === "user"
                ? "border-b-2 border-blue-500 text-blue-500"
                : "text-gray-500"
            }`}
          >
            Của tôi ({templates.user.length})
          </button>
          <button
            onClick={() => setActiveTab("public")}
            className={`px-4 py-2 font-semibold ${
              activeTab === "public"
                ? "border-b-2 border-blue-500 text-blue-500"
                : "text-gray-500"
            }`}
          >
            Công khai ({templates.public.length})
          </button>
        </div>

        <div className="space-y-2 max-h-64 overflow-y-auto">
          {(activeTab === "user" ? templates.user : templates.public).map((template) => (
            <div
              key={template._id}
              className="p-3 border border-gray-200 dark:border-gray-700 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors"
            >
              <div className="flex items-start justify-between">
                <div className="flex-1">
                  <h4 className="font-semibold">{template.name}</h4>
                  {template.description && (
                    <p className="text-sm text-gray-500 mt-1">{template.description}</p>
                  )}
                  {template.isPublic && (
                    <span className="text-xs text-blue-500 mt-1 inline-flex items-center gap-1">
                      <Star size={12} />
                      Công khai
                    </span>
                  )}
                </div>
                <div className="flex gap-2">
                  <button
                    onClick={() => handleUseTemplate(template._id)}
                    className="px-3 py-1 bg-green-500 text-white rounded text-sm hover:bg-green-600"
                  >
                    Dùng
                  </button>
                  {activeTab === "user" && (
                    <button
                      onClick={() => handleDelete(template._id)}
                      className="p-1 text-red-500 hover:bg-red-50 rounded"
                    >
                      <Trash2 size={16} />
                    </button>
                  )}
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center p-4 z-50">
          <div className="bg-white dark:bg-gray-800 rounded-2xl p-6 max-w-2xl w-full max-h-[90vh] overflow-y-auto">
            <div className="flex justify-between items-center mb-4">
              <h3 className="text-xl font-bold">Tạo Template</h3>
              <button onClick={() => setShowModal(false)}>
                <X size={24} />
              </button>
            </div>
            <form onSubmit={handleCreateTemplate} className="space-y-4">
              <div>
                <label className="block text-sm font-semibold mb-2">Tên template</label>
                <input
                  type="text"
                  value={formData.name}
                  onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                  required
                  className="w-full px-4 py-2 border-2 border-gray-200 dark:border-gray-600 dark:bg-gray-700 dark:text-white rounded-lg"
                />
              </div>
              <div>
                <label className="block text-sm font-semibold mb-2">Mô tả</label>
                <input
                  type="text"
                  value={formData.description}
                  onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                  className="w-full px-4 py-2 border-2 border-gray-200 dark:border-gray-600 dark:bg-gray-700 dark:text-white rounded-lg"
                />
              </div>
              <div>
                <label className="block text-sm font-semibold mb-2">Tiêu đề mặc định</label>
                <input
                  type="text"
                  value={formData.title}
                  onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                  className="w-full px-4 py-2 border-2 border-gray-200 dark:border-gray-600 dark:bg-gray-700 dark:text-white rounded-lg"
                />
              </div>
              <div>
                <label className="block text-sm font-semibold mb-2">Nội dung mặc định</label>
                <textarea
                  value={formData.content}
                  onChange={(e) => setFormData({ ...formData, content: e.target.value })}
                  rows={5}
                  className="w-full px-4 py-2 border-2 border-gray-200 dark:border-gray-600 dark:bg-gray-700 dark:text-white rounded-lg"
                />
              </div>
              <button
                type="submit"
                className="w-full bg-blue-500 text-white py-2 rounded-lg hover:bg-blue-600"
              >
                Tạo Template
              </button>
            </form>
          </div>
        </div>
      )}
    </>
  );
};

export default Templates;
